import { Component } from "react";
import "./ContactPage.css";


class ContactPage extends Component{
    render(){
        return(
            <div className="contact-page-main-bg-container">
                <div className="contact-banner-img">
                    <h1 className="contact-banner-heading">Contact Us</h1>
                </div>

                <div>
                    <h2>HAVE ANY QUESTIONS?</h2>
                    <p>Want to know about any of our ingredients or suppliers? Or just want to say anything? send us a message below and we'll get right back to you...  </p>

                    <form>
                        <label>Email</label>
                        
                    </form>
                </div>


            </div>
        )
    }
}

export default ContactPage;
